INSERT INTO `createur` (`id_createur`, `id_utilisateur`, `id_createur_type`, `nom_createur`, `photo_createur`, `description_createur_court_fr`, `description_createur_court_nl`, `description_createur_court_us`, `description_createur_court_es`, `description_createur_court_de`, `description_createur_long_fr`, `description_createur_long_nl`, `description_createur_long_us`, `description_createur_long_es`, `description_createur_long_de`, `createur_site_internet`, `createur_email`) VALUES
(1, 7, '3', 'GEOPICS', 'icon_geopics.png', 'Créateur de balades interactives', NULL, NULL, NULL, NULL, 'Geopics vous permet de créer ou de participer à des balades interactives et personnalisées. Géopics s’adresse aux particuliers, entreprises et organisations pour dynamiser événements, loisirs et découvertes locales.', '0', NULL, NULL, NULL, 'https://www.geopics.be', 'contact@geopics.be'),
(2, 5, '2', 'MaTélé', 'matele-logo-couleur.png', 'Télévision locale de l\'arrondissement de Dinant', 'Lokale televisie van het arrondissement Dinant', 'Local television of the Dinant district', 'Televisión local del distrito de Dinant', 'Lokales Fernsehen des Bezirks Dinant', 'Matélé est la chaîne de télévision belge régionale diffusée dans l\'arrondissement de Dinant, en province de Namur. Elle fait partie du Réseau des Médias de Proximité. ', 'Matélé is de regionale Belgische televisiezender die uitzendt in het arrondissement Dinant, in de provincie Namen. Het maakt deel uit van het Netwerk van Nabijheidsmedia.', 'Matélé is the regional Belgian television channel broadcasting in the Dinant district, in the province of Namur. It is part of the Proximity Media Network.', 'Matélé es el canal de televisión regional belga que se emite en el distrito de Dinant, en la provincia de Namur. Forma parte de la Red de Medios de Proximidad.', 'Matélé ist der regionale belgische Fernsehsender, der im Bezirk Dinant, in der Provinz Namur, ausgestrahlt wird. Es ist Teil des Netzwerks der Nähemedien.', 'https://www.matele.be/homepage', 'info@matele.be'),
(3, 38, '1', 'dubois&co ', NULL, '', NULL, NULL, NULL, NULL, '', '0', NULL, NULL, NULL, 'web2', 'mail2'),
(4, 2, '1', 'test aurore', NULL, '', NULL, NULL, NULL, NULL, '', '0', NULL, NULL, NULL, 'web', 'mail'),
