(184, 'deplacement_vers_balises', 'Déplacez-vous physiquement vers les balises.', 'Beweeg fysiek naar de bakens.', 'Physically move to the beacons.', 'Muévete físicamente hacia las balizas.', 'Bewegen Sie sich physisch zu den Markierungen.'),
(185, 'proximite_balise_cliquer', 'Une fois à proximité d’une balise : Cliquez dessus', 'Zodra u in de buurt van een baken bent: Klik erop', 'Once near a beacon: Click on it', 'Una vez cerca de una baliza: Haz clic en ella', 'Sobald Sie sich in der Nähe einer Markierung befinden: Klicken Sie darauf'),
(186, 'cliquez_activer_spot', 'Cliquez ensuite sur « Activer le spot ! ».', 'Klik vervolgens op \"Spot activeren!\".', 'Then click on \"Activate the spot!\".', 'Luego haz clic en \"¡Activar el spot!\".', 'Klicken Sie dann auf \"Spot aktivieren!\".'),
(187, 'bouton_actif', 'Important : Ce bouton ne sera actif que lorsque vous serez assez proche du point indiqué.', 'Belangrijk: Deze knop is alleen actief wanneer u dicht genoeg bij het aangegeven punt bent.', 'Important: This button will only be active when you are close enough to the indicated point.', 'Importante: Este botón solo estará activo cuando estés lo suficientemente cerca del punto indicado.', 'Wichtig: Dieser Button ist nur aktiv, wenn Sie sich nahe genug am angegebenen Punkt befinden.'),
(188, 'page_aide_menu', 'Une page d\'aide est accessible via le menu pour toute information complémentaire.', 'Een help-pagina is toegankelijk via het menu voor aanvullende informatie.', 'A help page is available through the menu for any additional information.', 'Una página de ayuda está disponible a través del menú para cualquier información adicional.', 'Eine Hilfeseite ist über das Menü für weitere Informationen zugänglich.'),
(189, 'cest_parti_bonne_aventure', 'C’est parti ! Bonne aventure !', 'Daar gaan we! Veel plezier!', 'Let\'s go! Have a great adventure!', '¡Vamos! ¡Buena aventura!', 'Los geht\'s! Viel Spaß bei deinem Abenteuer!'),
(190, 'ok_compris', 'Ok, j\'ai compris!', 'Ok, ik begrijp het!', 'Ok, I understand!', '¡Ok, lo entiendo!', 'Ok, ich habe es verstanden!'),
(191, 'vous_avez_besoin_daide', 'Vous avez besoin d\'aide ?', 'Heb je hulp nodig?', 'Do you need help?', '¿Necesitas ayuda?', 'Brauchst du Hilfe?'),
(192, 'nous_vous_invitons_a_consulter_les_informations_ci-dessous', 'Nous vous invitons à consulter les informations ci-dessous :', 'We nodigen u uit om de onderstaande informatie te bekijken:', 'We invite you to check the information below:', 'Le invitamos a consultar la información a continuación:', 'Wir laden Sie ein, die unten stehenden Informationen zu lesen:'),
(193, '1_choisir_sa_balade', '1. Choisir sa balade', '1. Kies uw wandeling', '1. Choose your walk', '1. Elige tu paseo', '1. Wählen Sie Ihren Spaziergang'),
(194, 'apres_connexion_selectionnez_recherche_balade', 'Après connexion, sélectionnez « Recherche balade ».', 'Na inloggen selecteert u \"Wandeling zoeken\".', 'After logging in, select \"Search walk\".', 'Después de iniciar sesión, seleccione \"Buscar paseo\".', 'Nach dem Einloggen wählen Sie „Spaziergang suchen“.'),
(195, 'chaque_balade_affiche_un_apercu_de_la_region_ou_elle_se_situe', 'Chaque balade affiche un aperçu de la région où elle se situe.', 'Elke wandeling toont een overzicht van de regio waar deze zich bevindt.', 'Each walk shows a preview of the region where it is located.', 'Cada paseo muestra una vista previa de la región donde se encuentra.', 'Jede Wanderung zeigt eine Vorschau der Region, in der sie sich befindet.'),
(196, 'vous_verrez_egalement', 'vous verrez également :', 'u zult ook zien :', 'you will also see :', 'también verá :', 'Sie werden auch sehen :'),
(197, 'le_nombre_de_balises_presentes_sur_le_parcours', 'Le nombre de balises présentes sur le parcours.', 'Het aantal markeringen op het parcours.', 'The number of markers on the course.', 'El número de marcas en el recorrido.', 'Die Anzahl der Markierungen auf der Strecke.'),
(198, 'la_duree_estimee_de_la_balade', 'La durée estimée de la balade.', 'De geschatte duur van de wandeling.', 'The estimated duration of the walk.', 'La duración estimada de la caminata.', 'Die geschätzte Dauer des Spaziergangs.'),
(199, 'le_tarif_de_participation', 'Le tarif de participation.', 'Het deelname tarief.', 'The participation fee.', 'La tarifa de participación.', 'Die Teilnahmegebühr.'),
(200, 'la_langue_disponible_pour_le_jeu', 'La langue disponible pour le jeu.', 'De taal beschikbaar voor het spel.', 'The language available for the game.', 'El idioma disponible para el juego.', 'Die für das Spiel verfügbare Sprache.'),
(201, 'utilisez_les_filtres_pour_affiner_votre_recherche_en_fonction_de_ces_criteres', 'Utilisez les filtres pour affiner votre recherche en fonction de ces critères.', 'Gebruik de filters om uw zoekopdracht te verfijnen op basis van deze criteria.', 'Use the filters to refine your search based on these criteria.', 'Utilice los filtros para afinar su búsqueda según estos criterios.', 'Verwenden Sie die Filter, um Ihre Suche anhand dieser Kriterien zu verfeinern.'),
(202, 'cliquez_sur_la_balade_souhaitee_pour_obtenir_plus_d_informations_notamment', 'Cliquez sur la balade souhaitée pour obtenir plus d\'informations, notamment :', 'Klik op de gewenste wandeling om meer informatie te krijgen, zoals:', 'Click on the desired walk to get more information, including:', 'Haga clic en la caminata deseada para obtener más información, incluyendo:', 'Klicken Sie auf den gewünschten Spaziergang, um mehr Informationen zu erhalten, wie:'),
(203, 'un_descriptif_detaillé_de_la_balade', 'Un descriptif détaillé de la balade.', 'Een gedetailleerde beschrijving van de wandeling.', 'A detailed description of the walk.', 'Una descripción detallada de la caminata.', 'Eine detaillierte Beschreibung des Spaziergangs.'),
(204, 'le_nom_de_la_personne_ou_de_l_organisme_qui_l_a_concue', 'Le nom de la personne ou de l’organisme qui l’a conçue.', 'De naam van de persoon of organisatie die het heeft ontworpen.', 'The name of the person or organization that designed it.', 'El nombre de la persona o la organización que lo diseñó.', 'Der Name der Person oder Organisation, die es entworfen hat.'),
(205, 'une_fois_sur_la_page_de_detail_de_la_balade_appuyez_sur_jouer_pour_commencer_l_aventure', 'Une fois sur la page de détail de la balade, appuyez sur « Jouer » pour commencer l’aventure !', 'Eenmaal op de detailpagina van de wandeling, druk op « Spelen » om het avontuur te starten!', 'Once on the walk detail page, press \"Play\" to start the adventure!', 'Una vez en la página de detalles de la caminata, presiona \"Jugar\" para comenzar la aventura!', 'Einmal auf der Detailseite des Spaziergangs, drücken Sie auf „Spielen“, um das Abenteuer zu beginnen!'),
