(15, 'La Gourm\' Rochefort (FR)\n', 'geopics_banniere.png', NULL, 'banniere_geopics_balade.svg', NULL, NULL, 'icon_geopics.png', 'icon_geopics_check.png', '50.15996127890005, 5.223330574309747', 'LA GOURMANDISE\nRue de Behogne, 24\n5580 Rochefort', 'icon_gourrm.png', '50.16004724580201, 5.223749884264268', 'cercle', '1000', NULL, 1, NULL, 'Géopics, La Gourmandise', 'gourmandise.css', '#25a2c3', '#E9F1FA', 1397, NULL, NULL, 1, NULL, 'rochefort.jpg', 'Partez à l\'aventure avec une balade interactive, offerte par le restaurant La Gourmandise à Rochefort. Cette expérience unique mêle jeu, découverte et histoire pour vous faire explorer les incontournables de la ville.', '02:30:00', NULL, 1, 0, NULL, 34, NULL, '', 'fr', 0, 'geopics_banniere.png', 0.0003, 1, 1),
