(63, 'La Gourm\' Rochefort (NL)\n', 'geopics_banniere.png', NULL, 'banniere_geopics_balade.svg', NULL, NULL, 'icon_geopics.png', 'icon_geopics_check.png', '50.15996127890005, 5.223330574309747', 'LA GOURMANDISE\nRue de Behogne, 24\n5580 Rochefort', 'icon_gourrm.png', '50.16004724580201, 5.223749884264268', 'cercle', '1000', NULL, 1, NULL, 'Géopics, La Gourmandise', 'gourmandise.css', '#25a2c3', '#E9F1FA', 1397, NULL, NULL, 1, NULL, 'rochefort.jpg', 'Ga op avontuur met een interactieve wandeling, aangeboden door restaurant La Gourmandise in Rochefort. Deze unieke ervaring combineert spel, ontdekking en geschiedenis om u de hoogtepunten van de stad te laten ontdekken.', '02:30:00', NULL, 1, 0, NULL, 34, NULL, '', 'nl', 0, 'geopics_banniere.png', 0.0003, 1, 1),
(64, 'La Gourm\' Rochefort (EN)\n', 'geopics_banniere.png', NULL, 'banniere_geopics_balade.svg', NULL, NULL, 'icon_geopics.png', 'icon_geopics_check.png', '50.15996127890005, 5.223330574309747', 'LA GOURMANDISE\nRue de Behogne, 24          5580 Rochefort', 'icon_gourrm.png', '50.16004724580201, 5.223749884264268', 'cercle', '1000', NULL, 1, NULL, 'Géopics, La Gourmandise', 'gourmandise.css', '#25a2c3', '#E9F1FA', 1397, NULL, NULL, 1, NULL, 'rochefort.jpg', 'Set off on an adventure with an interactive walk, offered by the restaurant La Gourmandise in Rochefort. This unique experience combines gameplay, discovery, and history to help you explore the must-sees of the city.\n', '02:30:00', NULL, 1, 0, NULL, 34, NULL, '', 'us', 0, 'geopics_banniere.png', 0.0003, 1, 1),
(82, 'Balade avec tous les jeux', 'geopics_banniere.png', NULL, 'banniere_geopics_balade.svg', '2026-03-17 14:51:00', '2026-03-18 14:51:00', 'icon_geopics.png', 'icon_geopics_check.png', '50.2240814,5.3428796', 'Rue des test', 'icon_gourrm.png', '50.2240814,5.3428796', 'Cercle', '2000', NULL, 1, NULL, 'Thème de test et problème', 'gourmandise.css', '#25a2c3', '#E9F1FA', 1804, NULL, NULL, 5, '', 'logo.png', 'Cette balade est une balade test pour décrire tout les problèmes des différents mode de jeu', '02:00:00', NULL, 3, 19, 1, 19, 1, 'NWNRJCQIXZNu96QaymShIbZFRUXeQF2n', 'fr', 1, 'geopics_banniere.png', 0.0003, NULL, 3);
