(24, 'Taquin', '', '', '', '50.15938047760647, 5.2648565625093084', 3, 7, 'Un taquin a reconstituer rapidement, si possible ! ', '', '', '', 'LOGO_MATELE_PUZZLE_0', '', '', '', 1, 180, '2024-01-17 15:46:09', 0, ''),
(25, 'Pendu', 'Indice : c\'est un canal de diffusion de Matélé.', '', '', '50.15960905764513, 5.265155234057317', 3, 14, 'Cliquez sur les lettres pour tenter de reformer le mot correct avant la pendaison du personnage.', 'Indice : c\'est un canal de diffusion de Matélé.', '', '', 'TELEVISION', '', '', '', 1, 0, '2024-01-17 15:47:06', 1, ''),
(26, 'Memory', '', '', '', '50.15910601842731, 5.2650566104367185', 3, 15, '5 paires', '', '', '', '', '', '', '', 1, 90, '2024-01-17 13:27:07', 1, ''),
(27, 'Géographie', '', '', '', '50.15958496301602, 5.264432773500801', 3, 5, 'Cliquez sur la carte pour localiser la commune de Rochefort dans l\'arrondissement de Dinant.', '', 'carte arrondissement tev v3.png', '', 'Rochefort', '', 'Félicitations, vous avez su replacer Rochefort sur la carte !', '', 5, 90, '2024-01-17 13:27:07', 1, ''),
(28, 'Vidéo', '', '', '', '50.15939319805219, 5.265118042442918', 3, 30, 'Visionnez la vidéo puis répondez aux questions suivantes.', 'Quel lieu n\'apparaît pas dans cette vidéo ?|De quelle couleur sont les cynorrhodons filmés au Belvédère ?|À quelle altitude culmine la Croix-Scaille ?', '240109 fiorine sequence contemplative.mp4', 'La vallée du Bocq à Purnode|Le Belvédère à Han-sur-Lesse|La Croix-Scaille à Gedinne|Jaune|Rose|Rouge|404 m|504 m|604 m', '1|6|8', '', '', '', 1, 0, '2024-01-17 13:27:07', 1, ''),
