(1260, 'Vidéo', 'Problème:\r\n- Chargement de l\'image au lancement -> OK\r\n- Chargement des propositions et question -> Pas OK\r\n- Boutons Valider/Abandoner Fonctionnel -> Pas OK\r\nA faire :\r\n- Charger les textes de proposition et de question\r\n- Faire des boutons fonctionnel', NULL, NULL, '50.21844931692872,5.3585446922524325', 82, 30, 'Vidéo ?', '', 'video.mp4', '', '', NULL, NULL, '', 1, 0, '2026-03-20 08:38:50', 1, 'nrLEYEgtBhIl1mk88utOi9Q6oRySexMK');
INSERT INTO `np_type_activite` (`id_type_activite`, `fichier_exploitation`, `nom_type_activite_fr`, `nom_type_activite_nl`, `nom_type_activite_us`, `nom_type_activite_es`, `nom_type_activite_de`, `commentaire_activite_fr`, `commentaire_activite_nl`, `commentaire_activite_us`, `commentaire_activite_es`, `commentaire_activite_de`, `img_description`, `pointer_activite`, `pointer_activite_check`, `afficher_info`) VALUES
(1, 'qcm_classique.php', 'Question choix multiples', 'Meerkeuzevraag', 'Multiple choice question', 'Pregunta de opción múltiple', 'Multiple-Choice-Frage', 'Fais réfléchir avec plusieurs propositions, où il faut identifier la bonne réponse.', 'Laat nadenken met meerdere keuzemogelijkheden, waarbij men het juiste antwoord moet herkennen.', 'Make people think with multiple options, where the correct answer must be identified.', 'Haz reflexionar con varias opciones, donde hay que identificar la respuesta correcta.', 'Regt zum Nachdenken an mit mehreren Antwortmöglichkeiten, bei denen die richtige Antwort gefunden werden muss.', NULL, NULL, NULL, 1),
(2, 'qcm_photo.php', 'Photo', 'Foto', 'Photo', 'Foto', 'Foto', 'Jeu interactif où les participants doivent identifier la bonne réponse en choisissant parmi plusieurs photos associées à une question.', 'Interactief spel waarbij de deelnemers het juiste antwoord moeten identificeren door te kiezen uit meerdere foto\'s die bij een vraag horen.', 'Interactive game where participants must identify the correct answer by choosing from several photos associated with a question.', 'Juego interactivo en el que los participantes deben identificar la respuesta correcta eligiendo entre varias fotos asociadas a una pregunta.', ' Interaktives Spiel, bei dem die Teilnehmer die richtige Antwort identifizieren müssen, indem sie aus mehreren Fotos wählen, die mit einer Frage verbunden sind.', NULL, NULL, NULL, 0),
(3, 'qcm_audio.php', 'Audio', 'Audio', 'Audio', 'Audio', 'Audio', 'Offre des contenus sonores pour écouter des informations ou des histoires liées aux spots pour répondre à la question.', 'Biedt geluidsinhoud aan om naar informatie of verhalen te luisteren die verband houden met de locaties om de vraag te beantwoorden.', 'Provides audio content to listen to information or stories related to the spots to answer the question.', 'Ofrece contenido sonoro para escuchar información o historias relacionadas con los lugares para responder a la pregunta.', 'Bietet Audioinhalte an, um Informationen oder Geschichten zu hören, die mit den Orten verbunden sind, um die Frage zu beantworten.', NULL, NULL, NULL, 1),
(4, 'vrai_faux.php', 'Vrai/Faux', 'Waar/Onwaar', 'True/False', 'Verdadero/Falso', 'Wahr/Falsch', 'Pose des questions simples nécessitant une réponse par vrai ou faux.', ' Stelt eenvoudige vragen die een antwoord vereisen met waar of onwaar.', 'Asks simple questions that require a true or false answer.', 'Plantea preguntas simples que requieren una respuesta de verdadero o falso.', 'Plantea preguntas simples que requieren una respuesta de verdadero o falso.', NULL, NULL, NULL, 1),
(5, 'carte_muette.php', 'Géographie', 'Geografie', 'Geography', 'Geografía', 'Geographie', 'Défi où les utilisateurs doivent identifier le lieu associé à une question spécifique.', 'Uitdaging waarbij de gebruikers de locatie moeten identificeren die bij een specifieke vraag hoort.', 'Challenge where users must identify the location associated with a specific question.', ' Desafío en el que los usuarios deben identificar el lugar asociado con una pregunta específica.', 'Herausforderung, bei der die Nutzer den Ort identifizieren müssen, der mit einer bestimmten Frage verbunden ist.', NULL, NULL, NULL, 1),
(6, 'texte_trous.php', 'Texte à trou', 'Tekst met ontbrekende woorden', 'Fill-in-the-blank text', 'Texto con huecos', 'Lückentext', 'Activité où les utilisateurs doivent compléter un texte en insérant les mots manquants dans les espaces prévus à cet effet.', 'Activiteit waarbij gebruikers een tekst moeten aanvullen door de ontbrekende woorden in de daarvoor bestemde ruimtes in te vullen.', 'Activity where users must complete a text by inserting the missing words into the designated spaces.', 'Actividad en la que los usuarios deben completar un texto insertando las palabras que faltan en los espacios previstos para ello.', 'Aktivität, bei der die Nutzer einen Text vervollständigen müssen, indem sie die fehlenden Wörter in die dafür vorgesehenen Lücken einfügen.\r\n', NULL, NULL, NULL, 0),
(7, 'taquin3x3.php', 'Taquin', 'Puzzel', 'Sliding Puzzle', 'Rompecabezas deslizante', 'Schiebepuzzle', 'Jeu de puzzle où les utilisateurs doivent reconstituer une image en déplaçant les pièces.', 'Puzzelspel waarbij gebruikers een afbeelding moeten samenstellen door de stukken te verplaatsen.', 'Puzzle game where users must reconstruct an image by moving the pieces.', 'Juego de rompecabezas en el que los usuarios deben reconstruir una imagen moviendo las piezas.', 'Puzzlespiel, bei dem die Nutzer ein Bild wiederherstellen müssen, indem sie die Teile verschieben.', NULL, NULL, NULL, 1),
(8, 'puzzle.php', 'Puzzle', 'Puzzel', 'Puzzle', 'Rompecabezas', 'Puzzle', 'Défi de reconstitution d\'une image ou d\'une carte à partir de pièces éparpillées.', 'Uitdaging om een afbeelding of kaart te reconstrueren uit verspreide stukken.', 'Challenge to reconstruct an image or map from scattered pieces.', 'Desafío para reconstruir una imagen o un mapa a partir de piezas dispersas.', 'Herausforderung, ein Bild oder eine Karte aus verstreuten Teilen wieder zusammenzusetzen.', NULL, NULL, NULL, 1),
(9, '7erreurs.php', '5 différences', '5 verschillen', '5 differences', '5 diferencias', '5 Unterschiede', 'Activité visuelle où les participants doivent trouver cinq différences entre deux images presque identiques.', 'Visuele activiteit waarbij de deelnemers vijf verschillen moeten vinden tussen twee bijna identieke afbeeldingen.', 'Visual activity where participants must find five differences between two nearly identical images.', 'Actividad visual en la que los participantes deben encontrar cinco diferencias entre dos imágenes casi idénticas.', 'Visuelle Aktivität, bei der die Teilnehmer fünf Unterschiede zwischen zwei fast identischen Bildern finden müssen.', NULL, NULL, NULL, 1),
(10, 'estimation.php', 'Estimation', 'Schatting', 'Estimation', 'Estimación', 'Schätzung', 'Jeu où les participants doivent deviner une quantité ou une mesure le plus précisément possible, comme le poids, la taille, le nombre d\'objets dans une image, ou le temps que prendra une activité.', 'Spel waarbij de deelnemers zo nauwkeurig mogelijk een hoeveelheid of maat moeten raden, zoals het gewicht, de grootte, het aantal objecten in een afbeelding, of de tijd die een activiteit zal duren.', 'Game where participants must guess a quantity or measurement as accurately as possible, such as weight, size, the number of objects in an image, or the time an activity will take.', 'Juego en el que los participantes deben adivinar una cantidad o medida lo más exactamente posible, como el peso, el tamaño, el número de objetos en una imagen o el tiempo que tomará una actividad.', 'Spiel, bei dem die Teilnehmer eine Menge oder ein Maß so genau wie möglich erraten müssen, wie das Gewicht, die Größe, die Anzahl der Objekte in einem Bild oder die Zeit, die eine Aktivität in Anspruch nehmen wird.', NULL, NULL, NULL, 1),
(11, 'classement_chrono.php', 'Classement chronologique', 'Chronologische volgorde', 'Chronological order', 'Orden cronológico', 'Chronologische Reihenfolge', 'Jeu où les participants doivent organiser des événements, des objets ou des images dans l\'ordre où ils se sont produits ou ont été créés. ', 'Spel waarbij de deelnemers gebeurtenissen, voorwerpen of afbeeldingen in de volgorde moeten plaatsen waarin ze hebben plaatsgevonden of zijn gemaakt.', 'Game where participants must organize events, objects, or images in the order in which they occurred or were created.', ' Juego en el que los participantes deben organizar eventos, objetos o imágenes en el orden en que ocurrieron o fueron creados.', 'Spiel, bei dem die Teilnehmer Ereignisse, Objekte oder Bilder in der Reihenfolge anordnen müssen, in der sie aufgetreten sind oder erstellt wurden.', NULL, NULL, NULL, 1),
(12, 'qcm_photo.php', 'Intrus photos', ' Foto-indringer', 'Photo intruder', 'Intruso de fotos', 'Foto-Eindringling', 'Jeu où les participants doivent identifier l\'élément qui ne correspond pas aux autres dans un ensemble de photos. ', 'Spel waarbij de deelnemers het element moeten identificeren dat niet bij de andere hoort in een reeks foto\'s.', 'Game where participants must identify the element that does not match the others in a set of photos.', 'Juego en el que los participantes deben identificar el elemento que no corresponde a los demás en un conjunto de fotos.', 'Spiel, bei dem die Teilnehmer das Element identifizieren müssen, das nicht zu den anderen in einer Reihe von Fotos passt.', NULL, NULL, NULL, 1),
(13, 'observation.php', 'Observation', 'Observatie', 'Observation', 'Observación', 'Beobachtung', 'Encourage les utilisateurs à observer leur environnement pour répondre à la question.', 'Moedigt gebruikers aan om hun omgeving te observeren om de vraag te beantwoorden.', 'Encourages users to observe their surroundings to answer the question.', 'Anima a los usuarios a observar su entorno para responder a la pregunta.', 'Ermutigt die Nutzer, ihre Umgebung zu beobachten, um die Frage zu beantworten.', NULL, NULL, NULL, 1),
(14, 'pendu.php', 'Pendu', 'Galgje', 'Hangman', 'Ahorcado', 'Galgenmännchen', 'Un jeu ludique où les participants doivent deviner un mot en sélectionnant des lettres, chaque erreur rapprochant un peu plus du \"pendu\".', 'Een leuk spel waarbij de deelnemers een woord moeten raden door letters te selecteren, waarbij elke fout hen dichter bij de \"galg\" brengt.', 'A fun game where participants must guess a word by selecting letters, with each mistake bringing them closer to the \"hangman.\"', 'Un juego divertido en el que los participantes deben adivinar una palabra seleccionando letras, y cada error los acerca un poco más al \"ahorcado\".', 'Ein lustiges Spiel, bei dem die Teilnehmer ein Wort erraten müssen, indem sie Buchstaben auswählen, wobei jeder Fehler sie dem \"Galgenmännchen\" näher bringt.', NULL, NULL, NULL, 1),
(15, 'memory.php', 'Mémory', 'Memory', 'Memory', 'Memoria', 'Memory', 'Jeu de mémoire visant à retrouver des paires d\'images ou d\'éléments similaires.', 'Geheugenspel waarbij het doel is om paren van afbeeldingen of vergelijkbare elementen te vinden.', 'Memory game aimed at finding pairs of images or similar elements.', 'Juego de memoria cuyo objetivo es encontrar pares de imágenes o elementos similares.', 'Gedächtnisspiel, bei dem es darum geht, Paare von Bildern oder ähnlichen Elementen zu finden.', NULL, NULL, NULL, 1),
(16, 'taquin2.php', 'Taquin', 'Schuifpuzzel', 'Sliding puzzle', 'Rompecabezas deslizante', 'Schiebepuzzle', 'Reformez le puzzle en faisant glisser les pièces.', ' Stel de puzzel opnieuw samen door de stukken te verschuiven.', 'eassemble the puzzle by sliding the pieces.', 'Reorganiza el rompecabezas deslizando las piezas.', 'Setzen Sie das Puzzle zusammen, indem Sie die Teile verschieben.\r\n', NULL, NULL, NULL, 0),
(17, 'lecture_silencieuse.php', 'Lecture silencieuse', 'Stil lezen', 'Silent reading', 'Lectura silenciosa', 'Stilles Lesen', 'Un texte à lire  avec  5 questions sur le texte.', 'Een tekst om te lezen met 5 vragen over de tekst.', 'A text to read with 5 questions about the text.', 'Un texto para leer con 5 preguntas sobre el texto.', 'Ein Text zum Lesen mit 5 Fragen zum Text.', NULL, NULL, NULL, 0),
(18, 'anagramme.php', 'Anagramme', 'Anagram', 'Anagram', 'Anagrama', 'Anagramm', 'Jeu de lettres où les participants doivent réarranger les lettres d\'un mot ou d\'une phrase pour former un nouveau mot ou une nouvelle phrase.', 'Letterspel waarbij de deelnemers de letters van een woord of zin moeten herschikken om een nieuw woord of een nieuwe zin te vormen.', 'Word game where participants must rearrange the letters of a word or phrase to form a new word or phrase.', 'Juego de letras en el que los participantes deben reorganizar las letras de una palabra o frase para formar una nueva palabra o frase.', 'Buchstabenspiel, bei dem die Teilnehmer die Buchstaben eines Wortes oder Satzes neu anordnen müssen, um ein neues Wort oder einen neuen Satz zu bilden.', NULL, NULL, NULL, 1),
(19, 'observation_continue.php', 'Observation en continu', 'Voortdurende observatie', 'Continuous observation', 'Observación continua', 'Ständige Beobachtung', 'Activité où les participants doivent identifier et retrouver des photos spécifiques tout au long de la balade.', 'Activiteit waarbij de deelnemers specifieke foto\'s moeten identificeren en terugvinden tijdens de hele wandeling.', 'Activity where participants must identify and find specific photos throughout the walk.', 'Actividad en la que los participantes deben identificar y encontrar fotos específicas a lo largo del paseo.', 'Aktivität, bei der die Teilnehmer während des gesamten Spaziergangs spezifische Fotos identifizieren und finden müssen.', NULL, 'continu.png', 'pointer_tev_check.png', 1),
(20, 'qcm_classique.php', 'Intrus', 'Indringer', ' Intruder', 'Intruso', 'Eindringling', 'Jeu de questions à choix multiples où les participants doivent identifier l\'option qui ne correspond pas aux autres parmi un ensemble proposé. ', 'Meerkeuzespel waarbij de deelnemers de optie moeten identificeren die niet bij de andere past uit een aangeboden reeks.', 'Multiple-choice game where participants must identify the option that does not match the others from a given set.', 'Juego de preguntas de opción múltiple en el que los participantes deben identificar la opción que no corresponde a las demás entre un conjunto propuesto.', 'Multiple-Choice-Spiel, bei dem die Teilnehmer die Option identifizieren müssen, die nicht zu den anderen in einem vorgeschlagenen Set passt.', NULL, NULL, NULL, 1),
(21, 'qcm_audio.php', 'Série de sons avec un intrus', 'Reeks van geluiden met een indringer', 'Series of sounds with an intruder', 'Serie de sonidos con un intruso', 'Reihe von Klängen mit einem Eindringling', 'Trouver l\'intrus', 'Vind de indringer', 'Find the intruder', 'Encuentra al intruso', 'Finde den Eindringling', NULL, NULL, NULL, 1),
(22, 'balade_temporelle.php', 'Balade temporelle', 'Tijdreis', 'Time walk', 'Paseo temporal', 'Zeitreise', 'Une archive photo localisée depuis son lieu de prise de vue.', 'Een fotoarchief gelokaliseerd vanuit de opnameplek', 'A geolocated photo archive from its capture point.', 'Archivo fotográfico geolocalizado desde el punto de captura.', 'Ein Fotoarchiv, lokalisiert vom Aufnahmestandort', NULL, NULL, NULL, 0),
(23, '', 'Poster une photo de vous', 'Plaats een foto van jezelf', 'Post a photo of yourself', 'Publica una foto de ti mismo', 'Poste ein Foto von dir', '', '', '', '', '', NULL, NULL, NULL, 0),
(25, 'classement_oui_non.php', 'Oui/non', 'Ja/nee', 'Yes/no', 'Sí/no', 'Ja/nein', 'Des questions nécessitant une simple réponse par oui ou non.', 'Vragen die een eenvoudig antwoord met ja of nee vereisen', 'Questions requiring a simple yes or no answer', 'Preguntas que requieren una simple respuesta de sí o no.', 'Fragen, die eine einfache Antwort mit ja oder nein erfordern', NULL, NULL, NULL, 1),
(26, 'qcm_video.php', 'Vidéo', 'Video', 'Video', 'Video', 'Video', 'Visionnez la vidéo et répondez aux questions.Bekijk de video en beantwoord de vragen.Bekijk de video en beantwoord de vragen.', 'Watch the video and answer the questions.', ' Mira el video y responde a las preguntas', 'Sehen Sie sich das Video an und beantworten Sie die Fragen.', '', NULL, NULL, NULL, 0),
(27, 'texte_trous_deroulant.php', 'Texte à trou', 'Tekst met ontbrekende woorden', 'Fill-in-the-blank text', 'Texto con huecos', 'Lückentext', 'Choisissez le bon mot dans la liste pour recomposer le texte. ', 'Kies het juiste woord uit de lijst om de tekst opnieuw samen te stellen.', 'Choose the correct word from the list to reconstruct the text.', 'Elige la palabra correcta de la lista para recomponer el texto.', 'Wählen Sie das richtige Wort aus der Liste, um den Text zu rekonstruieren.', NULL, NULL, NULL, 1),
(28, 'qcm_audio.php', 'QCM audio', 'Audio meerkeuzetoets', 'Audio multiple-choice quiz', 'Audio cuestionario de opción múltiple', 'Audio-Multiple-Choice-Frage', 'Un son, trois propositions écrites! Cliquez sur la bonne réponse.', 'Een geluid, drie geschreven voorstellen! Klik op het juiste antwoord.', 'One sound, three written options! Click on the correct answer.', 'Un sonido, tres opciones escritas! Haz clic en la respuesta correcta.', 'Ein Ton, drei schriftliche Vorschläge! Klicken Sie auf die richtige Antwort.', NULL, NULL, NULL, 0),
(30, 'question_reponse.php', 'Vidéo', 'Video', 'Video', 'Video', 'Video', 'Une vidéo et des questions basées sur le contenu observé. ', 'Een video en vragen op basis van de waargenomen inhoud.', 'A video and questions based on the observed content.', 'Un video y preguntas basadas en el contenido observado.', 'Ein Video und Fragen basierend auf dem beobachteten Inhalt.', NULL, NULL, NULL, 1);
INSERT INTO `sponsors` (`id_sponsor`, `nom_sponsor`, `id_createur_type`, `photo_sponsor`, `description_sponsor_court_fr`, `description_sponsor_court_nl`, `description_sponsor_court_us`, `description_sponsor_court_es`, `description_sponsor_court_de`, `description_sponsor_long_fr`, `description_sponsor_long_nl`, `description_sponsor_long_us`, `description_sponsor_long_es`, `description_sponsor_long_de`, `sponsor_site_internet`) VALUES
(1, 'La Gourmandise', 4, 'gourmandise_logo.png', 'La Gourmandise est un restaurant coquet situé en plein cœur de Rochefort.', 'La Gourmandise is een gezellig restaurant in het hart van Rochefort.', 'La Gourmandise is a charming restaurant located in the heart of Rochefort.', 'La Gourmandise es un restaurante acogedor ubicado en el corazón de Rochefort.', 'La Gourmandise ist ein gemütliches Restaurant im Herzen von Rochefort.', 'Un endroit propice pour régaler vos papilles gustatives grâce à une cuisine de terroir, réalisée avec des produits frais et locaux.', 'Een plek om je smaakpapillen te verwennen met streekgerechten, bereid met verse, lokale producten.', 'A place to delight your taste buds with local cuisine made from fresh, regional ingredients.', 'Un lugar para deleitar tu paladar con cocina local elaborada con productos frescos y locales.', 'Ein Ort, um Ihren Gaumen mit regionaler Küche aus frischen, lokalen Produkten zu verwöhnen.', 'https://www.la-gourmandise.be/'),
(2, 'MaTélé', 2, 'TEV logo.png', 'Télévision locale de l\'arrondissement de Dinant', 'Lokale televisie van het arrondissement Dinant', 'Local television of the Dinant district', 'Televisión local del distrito de Dinant', 'Lokales Fernsehen des Bezirks Dinant', 'Matélé est la chaîne de télévision belge régionale diffusée dans l\'arrondissement de Dinant, en province de Namur. Elle fait partie du Réseau des Médias de Proximité. ', 'Matélé is de regionale Belgische televisiezender die uitzendt in het arrondissement Dinant, in de provincie Namen. Het maakt deel uit van het Netwerk van Nabijheidsmedia.', 'Matélé is the regional Belgian television channel broadcasting in the Dinant district, in the province of Namur. It is part of the Proximity Media Network.', 'Matélé es el canal de televisión regional belga que se emite en el distrito de Dinant, en la provincia de Namur. Forma parte de la Red de Medios de Proximidad.', 'Matélé ist der regionale belgische Fernsehsender, der im Bezirk Dinant, in der Provinz Namur, ausgestrahlt wird. Es ist Teil des Netzwerks der Nähemedien.', 'https://www.matele.be/homepage'),
(3, 'NEO-PLANNER SRL', 3, 'neo_planner_srl.png', 'Neo-Planner est la société à l\'origine  du développement de GEOPICS.BE.\r\nNeo-Planner SRL est une société belge de développement informatique spécialisée dans la création de logiciels sur mesure pour PME.\r\n', 'Neo-Planner is het bedrijf achter de ontwikkeling van GEOPICS.BE. Neo-Planner SRL is een Belgisch softwareontwikkelingsbedrijf gespecialiseerd in het creëren van op maat gemaakte softwareoplossingen voor KMO\'s.', 'Neo-Planner is the company behind the development of GEOPICS.BE. Neo-Planner SRL is a Belgian software development company specialized in creating custom software solutions for SMEs.', 'Neo-Planner es la empresa responsable del desarrollo de GEOPICS.BE. Neo-Planner SRL es una empresa belga de desarrollo de software especializada en la creación de soluciones de software a medida para PYME.', 'Neo-Planner ist das Unternehmen hinter der Entwicklung von GEOPICS.BE. Neo-Planner SRL ist ein belgisches Softwareentwicklungsunternehmen, das sich auf die Erstellung maßgeschneiderter Softwarelösungen für KMU spezialisiert hat.', '', '', '', '', '', 'https://www.neo-planner.eu');
